// MHPCO Claim Office implementation

export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type Customer = {
  yearsWithMHPCO: number;
};

export type QuoteStep = {
  op: "quote";
  items: Item[];
};

export type DamageEntry = {
  itemType: string;
  amount: number;
};

export type Incident = {
  cause: string;
  damages: DamageEntry[];
};

export type ClaimStep = {
  op: "claim";
  policy: number;
  incident: Incident;
};

export type Step = QuoteStep | ClaimStep;

export type Scenario = {
  customer: Customer;
  steps: Step[];
};

export type QuoteResult = { premium: number };
export type ClaimResult = { payout: number; remainingCap: number };
export type StepResult = QuoteResult | ClaimResult;

export type ScenarioResult = {
  results: StepResult[];
};

const MAIN_ITEM_VALUES: Record<string, { value: number; basePremium: number }> = {
  sword: { value: 1000, basePremium: 100 },
  amulet: { value: 600, basePremium: 60 },
  staff: { value: 800, basePremium: 80 },
  potion: { value: 400, basePremium: 40 },
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_VALUE = 250;
const COMPONENT_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60;
const DEDUCTIBLE = 100;
const PROCESSING_FEE = 5;

function isMainItem(type: string): boolean {
  return type in MAIN_ITEM_VALUES;
}

function isComponent(type: string): boolean {
  return COMPONENT_TYPES.has(type);
}

function isKnownType(type: string): boolean {
  return isMainItem(type) || isComponent(type);
}

// Insurance value for a single item (used for sum & cap)
function itemInsuranceValue(item: Item): number {
  if (isMainItem(item.type)) return MAIN_ITEM_VALUES[item.type].value;
  if (isComponent(item.type)) return COMPONENT_VALUE;
  throw new Error(`Unknown item type: ${item.type}`);
}

// Sum of insurance values across the policy's items
export function insuranceSum(items: Item[]): number {
  let sum = 0;
  for (const item of items) {
    sum += itemInsuranceValue(item);
  }
  return sum;
}

// Compute base premium for a single main item (no surcharges yet)
function mainItemBasePremium(item: Item): number {
  return MAIN_ITEM_VALUES[item.type].basePremium;
}

// Compute item base premium with item-specific surcharges (curse, high enchantment)
function mainItemPremiumWithItemSurcharges(item: Item): number {
  const base = mainItemBasePremium(item);
  let total = base;
  if (item.cursed) total += base * 0.5;
  if (item.enchantment !== undefined && item.enchantment >= 5) total += base * 0.3;
  return total;
}

// Compute components premium for the items list, applying the block discount.
// "Alike" components = same type. Each group of 3 same-type components gets the block premium.
function componentsPremium(items: Item[]): number {
  const counts = new Map<string, number>();
  for (const item of items) {
    if (isComponent(item.type)) {
      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
    }
  }
  let total = 0;
  for (const [, count] of counts) {
    const blocks = Math.floor(count / 3);
    const remainder = count % 3;
    if (blocks > 0 && remainder === 0 && count === 3) {
      // Spec: block applies only at exactly 3; 4 runes -> 100G, no block.
      // 6 runes? Spec doesn't say. We follow: only exactly 3 gets the block.
      // But "3 runes + 3 moonstones → 120 G base premium (two separate blocks)" so
      // two groups of exactly 3 each apply.
      total += COMPONENT_BLOCK_PREMIUM;
    } else {
      total += count * COMPONENT_PREMIUM;
    }
  }
  return total;
}

// Policy base premium = sum of item base premiums (including curse/high-enchant on main items)
// plus components premium with block discount.
function policyBasePremiumWithItemSurcharges(items: Item[]): number {
  let total = 0;
  for (const item of items) {
    if (isMainItem(item.type)) {
      total += mainItemPremiumWithItemSurcharges(item);
    }
  }
  total += componentsPremium(items);
  return total;
}

// Round in MHPCO's favor: premiums round UP, payouts round DOWN.
function roundPremium(value: number): number {
  return Math.ceil(value);
}

function roundPayout(value: number): number {
  return Math.floor(value);
}

export type QuoteContext = {
  yearsWithMHPCO: number;
  isFirstContract: boolean;
};

export function computePremium(items: Item[], context: QuoteContext): number {
  // Validate item types
  for (const item of items) {
    if (!isKnownType(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }

  if (items.length === 0) {
    return PROCESSING_FEE;
  }

  // Start with policy base premium incorporating item-specific surcharges
  let premium = policyBasePremiumWithItemSurcharges(items);

  // Policy-wide modifiers
  // Loyalty: ≥2 years -> 20% discount
  if (context.yearsWithMHPCO >= 2) {
    premium -= premium * 0.2;
  }

  // First insurance: 10% surcharge per item (each item in a quote is treated as a first insurance)
  // Per the spec: "each item in a `quote` is treated as a first insurance, regardless of customer history"
  // The 10% is on the policy base premium? Or per item? Let's look at example:
  // newcomer cursed sword: 100 base + 50 curse + 10 first insurance = 160 + 5 = 165
  // The "10 G first insurance" = 10% of 100 G base premium of the sword
  // long-standing: 100 + 50 + 30 - 20 + 10 - 15 = 155 + 5 = 160
  // 20 loyalty = 20% of base 100 = 20
  // 10 first insurance = 10% of base 100 = 10
  // 15 follow-up = 15% of base 100 = 15
  // So percentages are all on the BASE premium of the item (100 G), not on cumulative.

  // Hmm. Reconsider. Let me re-do.
  // It seems all percentages are applied to the BASE premium (of each item), not cumulatively.
  // newcomer: 100 (base) + 50 (50% of 100 curse) + 10 (10% of 100 first insurance) = 160 + 5 = 165 ✓
  // long-standing: 100 (base) + 50 (curse 50% of 100) + 30 (high-ench 30% of 100)
  //                - 20 (loyalty 20% of 100) + 10 (first ins 10% of 100) - 15 (follow-up 15% of 100)
  //                = 155 + 5 = 160 ✓
  // So modifiers apply to the BASE premium of the item, not multiplicatively.
  // BUT for multi-item: "the cursed surcharge adds 50 G (50 % of the cursed sword's base premium,
  //                       not of the policy total)"
  // Item-specific (cursed, high enchant): 50%/30% of the affected item's base premium.
  // Policy-wide (loyalty, first ins, follow-up): "apply to the policy base premium (the sum of all item base premiums)"
  // So loyalty 20% × policy base, first ins 10% × policy base, follow-up 15% × policy base.
  // Let me re-verify with newcomer:
  // policy base = 100 (sword). loyalty: 0yrs no. first ins: yes +10% of 100 = 10. follow-up: no.
  // item-specific: curse +50% of 100 = 50.
  // Total: 100 + 50 + 10 = 160 + 5 = 165 ✓
  // Long-standing (second quote):
  // policy base = 100. loyalty +20% of 100 (as discount) = -20. first ins: yes +10 = 10. follow-up: yes -15.
  // item-specific: curse +50, high-ench +30.
  // Total: 100 - 20 + 10 - 15 + 50 + 30 = 155 + 5 = 160 ✓
  // And multi-item: "policy covers cursed sword (100) and plain amulet (60) → policy base 160;
  //   cursed surcharge 50 (50% of cursed sword's base) → 210 before further modifiers and fee"
  // So 160 + 50 = 210. No other modifiers mentioned. Good.

  // Restart calculation properly.
  return PROCESSING_FEE; // placeholder, will be overwritten by caller using computePremiumProper
}

// Recomputed properly
export function computePremiumProper(items: Item[], context: QuoteContext): number {
  for (const item of items) {
    if (!isKnownType(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }

  if (items.length === 0) {
    return PROCESSING_FEE;
  }

  // Policy base premium: sum of item base premiums (without item-specific surcharges)
  // For components, apply the block discount at this level too.
  let policyBase = 0;
  for (const item of items) {
    if (isMainItem(item.type)) {
      policyBase += mainItemBasePremium(item);
    }
  }
  policyBase += componentsPremium(items);

  let premium = policyBase;

  // Item-specific surcharges (each based on that item's own base premium)
  for (const item of items) {
    if (isMainItem(item.type)) {
      const base = mainItemBasePremium(item);
      if (item.cursed) premium += base * 0.5;
      if (item.enchantment !== undefined && item.enchantment >= 5) premium += base * 0.3;
    }
    // Components don't have curse/enchant modifiers per the spec
  }

  // Policy-wide modifiers (on policyBase)
  if (context.yearsWithMHPCO >= 2) {
    premium -= policyBase * 0.2;
  }
  if (context.isFirstContract) {
    premium += policyBase * 0.1;
  } else {
    // every contract after the first gets 15% follow-up discount
    premium -= policyBase * 0.15;
  }
  // First insurance surcharge: "A first insurance carries a 10% initial assessment surcharge"
  // "each item in a `quote` is treated as a first insurance, regardless of customer history"
  // So the 10% first insurance always applies to each item's base premium.
  // Wait — re-reading the integration example:
  // long-standing: +10 G first insurance, on a sword (base 100). 10% of 100 = 10.
  // So first insurance is per-item, 10% of item base.
  // For newcomer cursed sword: +10 G first insurance. Also 10% of 100.
  // So independent of customer history, every item gets +10% of its base premium as "first insurance".
  // That replaces the `isFirstContract` notion above.

  // Let me recompute. Strip the isFirstContract logic from above and use a clean version.

  return Math.ceil(premium); // placeholder
}

