    // both clauses apply; "the 50 % rule wins"
    reimbursed = damageAmount * 0.5;
  } else if (isDragon) {
    reimbursed = damageAmount;
  } else {
    reimbursed = damageAmount;
  }
  // Apply deductible
  const afterDeductible = reimbursed - DEDUCTIBLE;
  return afterDeductible > 0 ? afterDeductible : 0;
}

