1	// MHPCO Claim Office implementation
2	
3	export type Item = {
4	  type: string;
5	  material?: string;
6	  enchantment?: number;
7	  cursed?: boolean;
8	};
9	
10	export type Customer = {
11	  yearsWithMHPCO: number;
12	};
13	
14	export type QuoteStep = {
15	  op: "quote";
16	  items: Item[];
17	};
18	
19	export type DamageEntry = {
20	  itemType: string;
21	  amount: number;
22	};
23	
24	export type Incident = {
25	  cause: string;
26	  damages: DamageEntry[];
27	};
28	
29	export type ClaimStep = {
30	  op: "claim";
31	  policy: number;
32	  incident: Incident;
33	};
34	
35	export type Step = QuoteStep | ClaimStep;
36	
37	export type Scenario = {
38	  customer: Customer;
39	  steps: Step[];
40	};
41	
42	export type QuoteResult = { premium: number };
43	export type ClaimResult = { payout: number; remainingCap: number };
44	export type StepResult = QuoteResult | ClaimResult;
45	
46	export type ScenarioResult = {
47	  results: StepResult[];
48	};
49	
50	const MAIN_ITEM_VALUES: Record<string, { value: number; basePremium: number }> = {
51	  sword: { value: 1000, basePremium: 100 },
52	  amulet: { value: 600, basePremium: 60 },
53	  staff: { value: 800, basePremium: 80 },
54	  potion: { value: 400, basePremium: 40 },
55	};
56	
57	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
58	const COMPONENT_VALUE = 250;
59	const COMPONENT_PREMIUM = 25;
60	const COMPONENT_BLOCK_PREMIUM = 60;
61	const DEDUCTIBLE = 100;
62	const PROCESSING_FEE = 5;
63	
64	function isMainItem(type: string): boolean {
65	  return type in MAIN_ITEM_VALUES;
66	}
67	
68	function isComponent(type: string): boolean {
69	  return COMPONENT_TYPES.has(type);
70	}
71	
72	function isKnownType(type: string): boolean {
73	  return isMainItem(type) || isComponent(type);
74	}
75	
76	function itemInsuranceValue(item: Item): number {
77	  if (isMainItem(item.type)) return MAIN_ITEM_VALUES[item.type].value;
78	  if (isComponent(item.type)) return COMPONENT_VALUE;
79	  throw new Error(`Unknown item type: ${item.type}`);
80	}
81	
82	export function insuranceSum(items: Item[]): number {
83	  let sum = 0;
84	  for (const item of items) {
85	    sum += itemInsuranceValue(item);
86	  }
87	  return sum;
88	}
89	
90	function mainItemBasePremium(item: Item): number {
91	  return MAIN_ITEM_VALUES[item.type].basePremium;
92	}
93	
94	// Components premium: groups of exactly 3 same-type components get the block premium.
95	// Spec: 4 runes → 100 G (no block), 7 runes → 175 G (no block).
96	// So only when count === 3 does the block apply. For >3, it's count * 25.
97	function componentsPremium(items: Item[]): number {
98	  const counts = new Map<string, number>();
99	  for (const item of items) {
100	    if (isComponent(item.type)) {
101	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
102	    }
103	  }
104	  let total = 0;
105	  for (const [, count] of counts) {
106	    if (count === 3) {
107	      total += COMPONENT_BLOCK_PREMIUM;
108	    } else {
109	      total += count * COMPONENT_PREMIUM;
110	    }
111	  }
112	  return total;
113	}
114	
115	export type QuoteContext = {
116	  yearsWithMHPCO: number;
117	  isFirstContract: boolean;
118	};
119	
120	export function computePremium(items: Item[], context: QuoteContext): number {
121	  for (const item of items) {
122	    if (!isKnownType(item.type)) {
123	      throw new Error(`Unknown item type: ${item.type}`);
124	    }
125	  }
126	
127	  if (items.length === 0) {
128	    return PROCESSING_FEE;
129	  }
130	
131	  // Policy base premium: sum of main item base premiums + components premium (with block discount)
132	  let policyBase = 0;
133	  for (const item of items) {
134	    if (isMainItem(item.type)) {
135	      policyBase += mainItemBasePremium(item);
136	    }
137	  }
138	  policyBase += componentsPremium(items);
139	
140	  let premium = policyBase;
141	
142	  // Item-specific surcharges (cursed, high enchantment) on the item's own base premium
143	  for (const item of items) {
144	    if (isMainItem(item.type)) {
145	      const base = mainItemBasePremium(item);
146	      if (item.cursed) premium += base * 0.5;
147	      if (item.enchantment !== undefined && item.enchantment >= 5) {
148	        premium += base * 0.3;
149	      }
150	    }
151	  }
152	
153	  // Policy-wide modifiers on the policy base premium
154	  if (context.yearsWithMHPCO >= 2) {
155	    premium -= policyBase * 0.2;
156	  }
157	  // First insurance surcharge: 10% — each item in a quote is treated as a first insurance,
158	  // so always applies (× policy base, which equals sum of 10%×item_base).
159	  premium += policyBase * 0.1;
160	  // Follow-up contract discount: 15% if not the customer's first contract
161	  if (!context.isFirstContract) {
162	    premium -= policyBase * 0.15;
163	  }
164	
165	  premium += PROCESSING_FEE;
166	
167	  return Math.ceil(premium);
168	}
169	
170	// ---------- Claims ----------
171	
172	export type Policy = {
173	  items: Item[];
174	  insuranceSum: number;
175	  cap: number;        // initial cap
176	  remainingCap: number;
177	};
178	
179	export function createPolicy(items: Item[]): Policy {
180	  const sum = insuranceSum(items);
181	  return {
182	    items,
183	    insuranceSum: sum,
184	    cap: sum * 2,
185	    remainingCap: sum * 2,
186	  };
187	}
188	
189	// Find a matching item in the policy for a damage entry by itemType.
190	// Spec: "if the damages array contains more entries of a given type than the policy actually covers,
191	// the CLI exits non-zero" — so we need to track how many of each type are available per claim.
192	function findItemForDamage(
193	  policy: Policy,
